<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Exams';
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf();executeSql('INSERT INTO exams(course_id,exam_name,exam_date,room_no,session) VALUES (?,?,?,?,?)',[(int)post('course_id','0')?:null,post('exam_name'),post('exam_date'),post('room_no'),post('session')]); header('Location: index.php'); exit;}
$courses=fetchAll('SELECT id,name FROM courses'); $rows=fetchAll('SELECT e.*,c.name course_name FROM exams e LEFT JOIN courses c ON c.id=e.course_id ORDER BY exam_date DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><div class="col"><input name="exam_name" class="form-control" placeholder="Exam"></div><div class="col"><select name="course_id" class="form-select"><?php foreach($courses as $c):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach;?></select></div><div class="col"><input type="date" name="exam_date" class="form-control"></div><div class="col"><input name="room_no" class="form-control" placeholder="Room"></div><div class="col"><select name="session" class="form-select"><option>Morning</option><option>Afternoon</option><option>Evening</option></select></div><div class="col"><button class="btn btn-primary">Create</button></div></form><hr><table class="table"><?php foreach($rows as $r):?><tr><td><?=e($r['exam_name'])?></td><td><?=e($r['course_name']??'')?></td><td><?=$r['exam_date']?></td><td><?=$r['room_no']?></td><td><?=$r['session']?></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
